package org.joda.time;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.joda.time.steps"
)
public class CucumberTest {
    // JUnit runner for Cucumber tests
}

package org.joda.time.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

import org.joda.time.DateTime;
import org.joda.time.DateTimeZone;
import org.joda.time.MutableDateTime;

public class StepDefs {

    private DateTimeZone timeZone;
    private DateTime dstDateTime;
    private DateTime standardDateTime;
    private DateTime resultDateTime;

    @Given("^the time zone is \"([^\"]*)\"$")
    public void the_time_zone_is(String zoneName) throws Throwable {
        timeZone = DateTimeZone.forID(zoneName);
    }

    @Given("^a DST overlap occurs at midnight on 2012-02-26 where clocks move back from 00:00 to 23:00$")
    public void a_DST_overlap_occurs_at_midnight_on_Feb_26() throws Throwable {
        // This is just documentation of the scenario condition
    }

    @Given("^a date-time \"([^\"]*)\" represents the first occurrence \\(DST\\)$")
    public void a_date_time_represents_the_first_occurrence_DST(String dateTimeStr) throws Throwable {
        dstDateTime = new DateTime(dateTimeStr, timeZone);
    }

    @Given("^a date-time \"([^\"]*)\" represents the second occurrence \\(Standard\\)$")
    public void a_date_time_represents_the_second_occurrence_Standard(String dateTimeStr) throws Throwable {
        standardDateTime = new DateTime(dateTimeStr, timeZone);
    }

    @When("^I adjust the DST date-time to the earlier offset at overlap$")
    public void i_adjust_the_DST_date_time_to_the_earlier_offset_at_overlap() throws Throwable {
        try {
            // Adjust from DST to earlier offset (in overlap period)
            long resultMillis = timeZone.adjustOffset(dstDateTime.getMillis(), true);
            resultDateTime = new DateTime(resultMillis, timeZone);
        } catch (Exception e) {
            // Handle exception if needed
            throw e;
        }
    }

    @Then("^the result should be the DST date-time \"([^\"]*)\"$")
    public void the_result_should_be_the_DST_date_time(String expectedDateTimeStr) throws Throwable {
        DateTime expectedDateTime = new DateTime(expectedDateTimeStr, timeZone);
        assertEquals("The adjusted time should match the expected DST time",
                     expectedDateTime.getMillis(), resultDateTime.getMillis());
        assertEquals("The adjusted timezone offset should match",
                     expectedDateTime.getZone().getOffset(expectedDateTime.getMillis()),
                     resultDateTime.getZone().getOffset(resultDateTime.getMillis()));
    }

    @Then("^the result should be the Standard date-time \"([^\"]*)\"$")
    public void the_result_should_be_the_Standard_date_time(String expectedDateTimeStr) throws Throwable {
        DateTime expectedDateTime = new DateTime(expectedDateTimeStr, timeZone);
        assertEquals("The adjusted time should match the expected Standard time",
                     expectedDateTime.getMillis(), resultDateTime.getMillis());
        assertEquals("The adjusted timezone offset should match",
                     expectedDateTime.getZone().getOffset(expectedDateTime.getMillis()),
                     resultDateTime.getZone().getOffset(resultDateTime.getMillis()));
    }

    @When("^I adjust the DST date-time to the later offset at overlap$")
    public void i_adjust_the_DST_date_time_to_the_later_offset_at_overlap() throws Throwable {
        try {
            // Adjust from DST to later offset (in overlap period)
            long resultMillis = timeZone.adjustOffset(dstDateTime.getMillis(), false);
            resultDateTime = new DateTime(resultMillis, timeZone);
        } catch (Exception e) {
            // Handle exception if needed
            throw e;
        }
    }

    @When("^I adjust the Standard date-time to the earlier offset at overlap$")
    public void i_adjust_the_Standard_date_time_to_the_earlier_offset_at_overlap() throws Throwable {
        try {
            // Adjust from Standard to earlier offset (in overlap period)
            long resultMillis = timeZone.adjustOffset(standardDateTime.getMillis(), true);
            resultDateTime = new DateTime(resultMillis, timeZone);
        } catch (Exception e) {
            // Handle exception if needed
            throw e;
        }
    }

    @When("^I adjust the Standard date-time to the later offset at overlap$")
    public void i_adjust_the_Standard_date_time_to_the_later_offset_at_overlap() throws Throwable {
        try {
            // Adjust from Standard to later offset (in overlap period)
            long resultMillis = timeZone.adjustOffset(standardDateTime.getMillis(), false);
            resultDateTime = new DateTime(resultMillis, timeZone);
        } catch (Exception e) {
            // Handle exception if needed
            throw e;
        }
    }
}

