/**
 * Adjusts the offset to be the earlier or later one during an overlap.
 *
 * @param instant  the instant to adjust
 * @param earlierOrLater  false for earlier, true for later
 * @return the adjusted instant millis
 */
public long adjustOffset(long instant, boolean earlierOrLater) {
    // Check if we're in a DST overlap (when clocks go back)
    int offset1 = getOffset(instant - DateTimeConstants.MILLIS_PER_HOUR);
    int offset2 = getOffset(instant);
    int offset3 = getOffset(instant + DateTimeConstants.MILLIS_PER_HOUR);

    // If no change in offset, not in an overlap
    if (offset2 == offset1 && offset2 == offset3) {
        return instant;
    }

    // Check if we are in an overlap situation
    // An overlap occurs when the same local time occurs twice due to DST ending
    if (offset1 > offset2 && offset2 == offset3) {
        // We are in an overlap region where the same local time occurs twice
        // For example, when clocks move from 00:00 to 23:00, the time from 23:00-00:00 may occur twice
        long localInstant = convertUTCToLocal(instant);

        // Get the offset that corresponds to the later (standard) time
        long standardOffsetInstant = convertLocalToUTC(localInstant, false, instant + DateTimeConstants.MILLIS_PER_HOUR);
        int standardOffset = getOffset(standardOffsetInstant);

        // Get the offset that corresponds to the earlier (DST) time  
        long dstOffsetInstant = convertLocalToUTC(localInstant, false, instant - DateTimeConstants.MILLIS_PER_HOUR);
        int dstOffset = getOffset(dstOffsetInstant);

        // If we're already at the correct offset based on earlierOrLater flag
        int currentOffset = offset2;

        // Determine which offset we want based on the earlierOrLater flag
        if (earlierOrLater) {
            // We want the later offset (the more positive/negative value depending on direction)
            // In case of overlap ending DST, the standard time offset is typically smaller (less negative)
            int desiredOffset = Math.min(dstOffset, standardOffset); // Standard time has smaller offset
            if (currentOffset != desiredOffset) {
                // Adjust to get the time with the desired offset
                return convertLocalToUTC(localInstant, false, instant - (desiredOffset - currentOffset));
            }
        } else {
            // We want the earlier offset (the less positive/more negative value depending on direction)
            // In case of overlap ending DST, the DST offset is typically larger (more negative)
            int desiredOffset = Math.max(dstOffset, standardOffset); // DST time has larger offset
            if (currentOffset != desiredOffset) {
                // Adjust to get the time with the desired offset
                return convertLocalToUTC(localInstant, false, instant - (desiredOffset - currentOffset));
            }
        }

        return instant;
    }

    // For the most common case or if we are not in an overlap
    return instant;
}

