/**
 * Adjusts the offset to be the earlier or later one during an overlap.
 *
 * @param instant  the instant to adjust
 * @param earlierOrLater  false for earlier, true for later
 * @return the adjusted instant millis
 */
public long adjustOffset(long instant, boolean earlierOrLater) {
    // Get the raw offset of the given instant
    int rawOffset = getOffset(instant);

    // Get the standard offset at this instant
    int standardOffset = getStandardOffset(instant);

    // If they're the same, we're not in a DST overlap, just return the instant
    if (rawOffset == standardOffset) {
        return instant;
    }

    // We are in a DST overlap situation (clocks fall back)
    // The same local time occurs with two different offsets

    // Convert to local time to get the "wall clock" time
    long localInstant = convertUTCToLocal(instant);

    // Now use convertLocalToUTC to get the specific occurrence we want
    // When there's an overlap, convertLocalToUTC with a reference instant
    // can distinguish between the earlier and later occurrences

    if (earlierOrLater) {
        // We want the "earlier" offset - this is the first occurrence during the day
        // This is typically the DST offset (larger offset value)
        // Use a reference instant that is known to be in the DST offset period
        return convertLocalToUTC(localInstant, false, instant - 1);
    } else {
        // We want the "later" offset - this is the second occurrence during the day
        // This is typically the Standard offset (smaller offset value)
        // Use a reference instant that is known to be in the Standard offset period 
        return convertLocalToUTC(localInstant, false, instant + 1);
    }
}

