/**
 * Adjusts the offset to be the earlier or later one during an overlap.
 *
 * @param instant  the instant to adjust
 * @param earlierOrLater  false for earlier, true for later
 * @return the adjusted instant millis
 */
public long adjustOffset(long instant, boolean earlierOrLater) {
    // Get the offset of this instant
    int offset = getOffset(instant);

    // Get the standard offset (non-DST) at this time
    int standardOffset = getStandardOffset(instant);

    // If they are the same, we're not in a DST overlap
    if (offset == standardOffset) {
        return instant;
    }

    // We are in a DST overlap (the same local time occurs twice)
    // Convert to local time
    long localInstant = convertUTCToLocal(instant);

    // The key insight is that convertLocalToUTC can distinguish between 
    // the two occurrences of the same local time based on the reference instant

    if (earlierOrLater) {
        // earlierOrLater=true means we want the later occurrence (second time the local time appears)
        // Use a reference that's after the overlap to get the later occurrence
        return convertLocalToUTC(localInstant, false, instant + 1);
    } else {
        // earlierOrLater=false means we want the earlier occurrence (first time the local time appears)  
        // Use a reference that's before the overlap to get the earlier occurrence
        return convertLocalToUTC(localInstant, false, instant - 1);
    }
}

