 * @param instant  the instant to adjust
 * @param earlierOrLater  true for earlier, false for later
 * @return the adjusted instant millis
 */
public long adjustOffset(long instant, boolean earlierOrLater) {
    // a bit messy, but will work in all non-pathological cases

    // evaluate 3 hours before and after to work out if anything is happening
    long instantBefore = instant - 3 * DateTimeConstants.MILLIS_PER_HOUR;
    long instantAfter = instant + 3 * DateTimeConstants.MILLIS_PER_HOUR;
    // Check if we're in an overlap by seeing if the offsets are different nearby
    if (getOffset(instantBefore) == getOffset(instantAfter)) {
        return instant;  // not an overlap (or no change in offset)
    }

    // work out range of instants that have duplicate local times
    long local = convertUTCToLocal(instant);
    // Use proper UTC instants as reference: true (earlier) -> instantBefore, false (later) -> instantAfter
    return convertLocalToUTC(local, false, earlierOrLater ? instantBefore : instantAfter);
}

